#include "EmitIR.hpp"
#include <llvm/IR/Constants.h>
#include <llvm/IR/Verifier.h>
#include <llvm/Transforms/Utils/ModuleUtils.h>

#define self (*this)

using namespace asg;

EmitIR::EmitIR(Obj::Mgr& mgr, llvm::LLVMContext& ctx, llvm::StringRef mid)
  : mMgr(mgr)
  , mMod(mid, ctx)
  , mCtx(ctx)
  , mIntTy(llvm::Type::getInt32Ty(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
{
}

llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls) {
    if (auto f = i->dcst<FunctionDecl>())
      declareFunction(f);
    else if (auto v = i->dcst<VarDecl>())
      declareGlobal(v);
    else
      ABORT();
  }

  for (auto&& i : tu->decls) {
    if (auto f = i->dcst<FunctionDecl>())
      emitFunctionBody(f);
  }
  return mMod;
}

//==============================================================================
// 类型
//==============================================================================

llvm::Type*
EmitIR::scalarType(Type::Spec spec)
{
  switch (spec) {
    case Type::Spec::kVoid:
      return llvm::Type::getVoidTy(mCtx);
    case Type::Spec::kChar:
      return llvm::Type::getInt8Ty(mCtx);
    case Type::Spec::kInt:
      return llvm::Type::getInt32Ty(mCtx);
    case Type::Spec::kLong:
    case Type::Spec::kLongLong:
      return llvm::Type::getInt64Ty(mCtx);
    default:
      ABORT();
  }
}

llvm::Type*
EmitIR::operator()(const Type* type)
{
  ASSERT(type);
  if (type->texp == nullptr)
    return scalarType(type->spec);

  Type subt;
  subt.spec = type->spec;
  subt.qual = type->qual;
  subt.texp = type->texp->sub;

  if (auto p = type->texp->dcst<PointerType>())
    return llvm::PointerType::get(mCtx, 0);

  if (auto p = type->texp->dcst<ArrayType>()) {
    ASSERT(p->len != ArrayType::kUnLen);
    return llvm::ArrayType::get(self(&subt), p->len);
  }

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    for (auto param : p->params)
      pty.push_back(self(param));
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  ABORT();
}

llvm::Type*
EmitIR::arrayElementType(const Type* type)
{
  ASSERT(type && type->texp);
  if (auto arr = type->texp->dcst<ArrayType>()) {
    Type elem;
    elem.spec = type->spec;
    elem.qual = type->qual;
    elem.texp = arr->sub;
    return self(&elem);
  }
  return scalarType(type->spec);
}

//==============================================================================
// 常量与辅助
//==============================================================================

llvm::Constant*
EmitIR::zeroOf(const Type* type)
{
  return llvm::Constant::getNullValue(self(type));
}

llvm::Constant*
EmitIR::constValue(Expr* expr)
{
  if (!expr)
    return nullptr;

  if (auto p = expr->dcst<IntegerLiteral>())
    return self(p);

  if (auto p = expr->dcst<ImplicitInitExpr>())
    return zeroOf(p->type);

  if (auto p = expr->dcst<ParenExpr>())
    return constValue(p->sub);

  if (auto p = expr->dcst<ImplicitCastExpr>()) {
    auto v = constValue(p->sub);
    if (!v)
      return nullptr;
    auto dstTy = self(p->type);
    if (v->getType() == dstTy)
      return v;
    if (auto ci = llvm::dyn_cast<llvm::ConstantInt>(v))
      return llvm::ConstantInt::get(dstTy, ci->getSExtValue(), true);
    return v;
  }

  if (auto p = expr->dcst<UnaryExpr>()) {
    auto v = llvm::dyn_cast_or_null<llvm::ConstantInt>(constValue(p->sub));
    if (!v)
      return nullptr;
    auto ty = self(p->type);
    switch (p->op) {
      case UnaryExpr::kPos:
        return llvm::ConstantInt::get(ty, v->getSExtValue(), true);
      case UnaryExpr::kNeg:
        return llvm::ConstantInt::get(ty, -v->getSExtValue(), true);
      case UnaryExpr::kNot:
        return llvm::ConstantInt::get(ty, v->isZero() ? 1 : 0);
      default:
        ABORT();
    }
  }

  if (auto p = expr->dcst<BinaryExpr>()) {
    if (p->op == BinaryExpr::kComma)
      return constValue(p->rht);
    auto l = llvm::dyn_cast_or_null<llvm::ConstantInt>(constValue(p->lft));
    auto r = llvm::dyn_cast_or_null<llvm::ConstantInt>(constValue(p->rht));
    if (!l || !r)
      return nullptr;
    auto a = l->getSExtValue();
    auto b = r->getSExtValue();
    std::int64_t res = 0;
    switch (p->op) {
      case BinaryExpr::kMul: res = a * b; break;
      case BinaryExpr::kDiv: res = a / b; break;
      case BinaryExpr::kMod: res = a % b; break;
      case BinaryExpr::kAdd: res = a + b; break;
      case BinaryExpr::kSub: res = a - b; break;
      case BinaryExpr::kGt: res = a > b; break;
      case BinaryExpr::kLt: res = a < b; break;
      case BinaryExpr::kGe: res = a >= b; break;
      case BinaryExpr::kLe: res = a <= b; break;
      case BinaryExpr::kEq: res = a == b; break;
      case BinaryExpr::kNe: res = a != b; break;
      case BinaryExpr::kAnd: res = (a != 0) && (b != 0); break;
      case BinaryExpr::kOr: res = (a != 0) || (b != 0); break;
      default: return nullptr;
    }
    return llvm::ConstantInt::get(self(p->type), res, true);
  }

  if (auto p = expr->dcst<InitListExpr>()) {
    if (p->list.empty())
      return zeroOf(p->type);
    return constValue(p->list.front());
  }

  return nullptr;
}

llvm::Constant*
EmitIR::constInit(const Type* type, Expr* init)
{
  if (!init)
    return zeroOf(type);

  if (auto arrTy = type->texp ? type->texp->dcst<ArrayType>() : nullptr) {
    Type elemTy;
    elemTy.spec = type->spec;
    elemTy.qual = type->qual;
    elemTy.texp = arrTy->sub;

    std::vector<llvm::Constant*> elems;
    if (auto list = init->dcst<InitListExpr>()) {
      for (std::uint32_t i = 0; i < arrTy->len; ++i) {
        if (i < list->list.size())
          elems.push_back(constInit(&elemTy, list->list[i]));
        else
          elems.push_back(zeroOf(&elemTy));
      }
    } else {
      return zeroOf(type);
    }
    return llvm::ConstantArray::get(
      llvm::cast<llvm::ArrayType>(self(type)), elems);
  }

  if (auto list = init->dcst<InitListExpr>()) {
    if (list->list.empty())
      return zeroOf(type);
    return constInit(type, list->list.front());
  }

  if (auto c = constValue(init)) {
    auto dst = self(type);
    if (c->getType() == dst)
      return c;
    if (auto ci = llvm::dyn_cast<llvm::ConstantInt>(c))
      return llvm::ConstantInt::get(dst, ci->getSExtValue(), true);
  }

  return zeroOf(type);
}

llvm::Value*
EmitIR::castTo(llvm::Value* value, llvm::Type* toType, bool isSigned)
{
  ASSERT(value && toType);
  auto from = value->getType();
  if (from == toType)
    return value;
  auto& irb = *mCurIrb;
  if (from->isIntegerTy() && toType->isIntegerTy()) {
    auto fromBits = from->getIntegerBitWidth();
    auto toBits = toType->getIntegerBitWidth();
    if (fromBits < toBits)
      return isSigned ? irb.CreateSExt(value, toType) : irb.CreateZExt(value, toType);
    if (fromBits > toBits)
      return irb.CreateTrunc(value, toType);
  }
  if (from->isPointerTy() && toType->isPointerTy())
    return value;
  return value;
}

llvm::Value*
EmitIR::emitCondition(Expr* obj)
{
  auto v = self(obj);
  auto& irb = *mCurIrb;
  if (v->getType()->isIntegerTy(1))
    return v;
  if (v->getType()->isIntegerTy())
    return irb.CreateICmpNE(v, llvm::ConstantInt::get(v->getType(), 0));
  if (v->getType()->isPointerTy())
    return irb.CreateICmpNE(v, llvm::ConstantPointerNull::get(llvm::PointerType::get(mCtx, 0)));
  ABORT();
}

bool
EmitIR::currentBlockTerminated() const
{
  auto bb = mCurIrb->GetInsertBlock();
  return bb && bb->getTerminator();
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);
  if (auto p = obj->dcst<DeclRefExpr>())
    return self(p);
  if (auto p = obj->dcst<ParenExpr>())
    return self(p);
  if (auto p = obj->dcst<UnaryExpr>())
    return self(p);
  if (auto p = obj->dcst<BinaryExpr>())
    return self(p);
  if (auto p = obj->dcst<CallExpr>())
    return self(p);
  if (auto p = obj->dcst<ImplicitCastExpr>())
    return self(p);
  if (auto p = obj->dcst<ImplicitInitExpr>())
    return self(p);
  if (auto p = obj->dcst<InitListExpr>()) {
    if (!p->list.empty())
      return self(p->list.front());
    return zeroOf(p->type);
  }
  ABORT();
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val, true);
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  ASSERT(obj->decl && obj->decl->any);
  return static_cast<llvm::Value*>(obj->decl->any);
}

llvm::Value*
EmitIR::operator()(ParenExpr* obj)
{
  return self(obj->sub);
}

llvm::Value*
EmitIR::operator()(ImplicitInitExpr* obj)
{
  return zeroOf(obj->type);
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  auto& irb = *mCurIrb;
  switch (obj->kind) {
    case ImplicitCastExpr::kLValueToRValue: {
      auto addr = emitLValue(obj->sub);
      return irb.CreateLoad(self(obj->type), addr);
    }
    case ImplicitCastExpr::kArrayToPointerDecay: {
      auto addr = emitLValue(obj->sub);
      auto subTy = obj->sub->type;
      if (subTy->texp && subTy->texp->dcst<ArrayType>()) {
        auto zero = llvm::ConstantInt::get(mIntTy, 0);
        return irb.CreateInBoundsGEP(self(subTy), addr, { zero, zero });
      }
      return addr;
    }
    case ImplicitCastExpr::kFunctionToPointerDecay:
      return self(obj->sub);
    case ImplicitCastExpr::kIntegralCast:
    case ImplicitCastExpr::kNoOp:
      return castTo(self(obj->sub), self(obj->type));
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto sub = self(obj->sub);
  switch (obj->op) {
    case UnaryExpr::kPos:
      return castTo(sub, self(obj->type));
    case UnaryExpr::kNeg:
      return irb.CreateNeg(castTo(sub, self(obj->type)));
    case UnaryExpr::kNot: {
      auto b = emitCondition(obj->sub);
      auto notv = irb.CreateNot(b);
      return irb.CreateZExt(notv, self(obj->type));
    }
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;

  if (obj->op == BinaryExpr::kAssign) {
    auto addr = emitLValue(obj->lft);
    auto val = self(obj->rht);
    auto dstTy = self(obj->lft->type);
    val = castTo(val, dstTy);
    irb.CreateStore(val, addr);
    return val;
  }

  if (obj->op == BinaryExpr::kComma) {
    self(obj->lft);
    return self(obj->rht);
  }

  if (obj->op == BinaryExpr::kIndex)
    return emitLValue(obj);

  if (obj->op == BinaryExpr::kAnd || obj->op == BinaryExpr::kOr) {
    auto resultAlloca = createEntryAlloca(self(obj->type), "logic.tmp");
    auto lhsBool = emitCondition(obj->lft);
    auto lhsI32 = irb.CreateZExt(lhsBool, self(obj->type));
    if (obj->op == BinaryExpr::kAnd)
      irb.CreateStore(llvm::ConstantInt::get(self(obj->type), 0), resultAlloca);
    else
      irb.CreateStore(llvm::ConstantInt::get(self(obj->type), 1), resultAlloca);

    auto rhsBb = llvm::BasicBlock::Create(mCtx, "logic.rhs", mCurFunc);
    auto endBb = llvm::BasicBlock::Create(mCtx, "logic.end", mCurFunc);
    if (obj->op == BinaryExpr::kAnd)
      irb.CreateCondBr(lhsBool, rhsBb, endBb);
    else
      irb.CreateCondBr(lhsBool, endBb, rhsBb);

    mCurIrb->SetInsertPoint(rhsBb);
    auto rhsBool = emitCondition(obj->rht);
    auto rhsI32 = irb.CreateZExt(rhsBool, self(obj->type));
    irb.CreateStore(rhsI32, resultAlloca);
    if (!currentBlockTerminated())
      irb.CreateBr(endBb);

    mCurIrb->SetInsertPoint(endBb);
    return irb.CreateLoad(self(obj->type), resultAlloca);
  }

  auto lhs = self(obj->lft);
  auto rhs = self(obj->rht);
  auto ty = lhs->getType();
  rhs = castTo(rhs, ty);

  switch (obj->op) {
    case BinaryExpr::kMul:
      return irb.CreateMul(lhs, rhs);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lhs, rhs);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lhs, rhs);
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lhs, rhs);
    case BinaryExpr::kSub:
      return irb.CreateSub(lhs, rhs);
    case BinaryExpr::kGt:
      return irb.CreateZExt(irb.CreateICmpSGT(lhs, rhs), self(obj->type));
    case BinaryExpr::kLt:
      return irb.CreateZExt(irb.CreateICmpSLT(lhs, rhs), self(obj->type));
    case BinaryExpr::kGe:
      return irb.CreateZExt(irb.CreateICmpSGE(lhs, rhs), self(obj->type));
    case BinaryExpr::kLe:
      return irb.CreateZExt(irb.CreateICmpSLE(lhs, rhs), self(obj->type));
    case BinaryExpr::kEq:
      return irb.CreateZExt(irb.CreateICmpEQ(lhs, rhs), self(obj->type));
    case BinaryExpr::kNe:
      return irb.CreateZExt(irb.CreateICmpNE(lhs, rhs), self(obj->type));
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto calleeValue = self(obj->head);
  auto callee = llvm::dyn_cast<llvm::Function>(calleeValue);
  if (!callee) {
    if (auto c = llvm::dyn_cast<llvm::ConstantExpr>(calleeValue))
      callee = llvm::dyn_cast<llvm::Function>(c->getOperand(0));
  }
  ASSERT(callee);

  std::vector<llvm::Value*> args;
  auto fty = callee->getFunctionType();
  for (std::size_t i = 0; i < obj->args.size(); ++i) {
    auto v = self(obj->args[i]);
    if (i < fty->getNumParams())
      v = castTo(v, fty->getParamType(i));
    args.push_back(v);
  }
  return mCurIrb->CreateCall(fty, callee, args);
}

llvm::Value*
EmitIR::emitLValue(Expr* obj)
{
  if (auto p = obj->dcst<DeclRefExpr>()) {
    ASSERT(p->decl && p->decl->any);
    return static_cast<llvm::Value*>(p->decl->any);
  }

  if (auto p = obj->dcst<ParenExpr>())
    return emitLValue(p->sub);

  if (auto p = obj->dcst<ImplicitCastExpr>()) {
    if (p->kind == ImplicitCastExpr::kNoOp)
      return emitLValue(p->sub);
    if (p->kind == ImplicitCastExpr::kArrayToPointerDecay)
      return self(p);
  }

  if (auto p = obj->dcst<BinaryExpr>()) {
    if (p->op == BinaryExpr::kIndex) {
      auto base = self(p->lft);
      auto idx = self(p->rht);
      idx = castTo(idx, mIntTy);
      return mCurIrb->CreateInBoundsGEP(self(p->type), base, idx);
    }
  }

  ABORT();
}

//==============================================================================
// 语句
//==============================================================================

void
EmitIR::operator()(Stmt* obj)
{
  if (currentBlockTerminated())
    return;

  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);
  if (auto p = obj->dcst<DeclStmt>())
    return self(p);
  if (auto p = obj->dcst<ExprStmt>())
    return self(p);
  if (auto p = obj->dcst<IfStmt>())
    return self(p);
  if (auto p = obj->dcst<WhileStmt>())
    return self(p);
  if (auto p = obj->dcst<BreakStmt>())
    return self(p);
  if (auto p = obj->dcst<ContinueStmt>())
    return self(p);
  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);
  if (obj->dcst<NullStmt>())
    return;

  ABORT();
}

void
EmitIR::operator()(CompoundStmt* obj)
{
  for (auto&& stmt : obj->subs) {
    self(stmt);
    if (currentBlockTerminated())
      break;
  }
}

void
EmitIR::operator()(DeclStmt* obj)
{
  for (auto decl : obj->decls)
    self(decl);
}

void
EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr)
    self(obj->expr);
}

void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc) : nullptr;
  auto endBb = llvm::BasicBlock::Create(mCtx, "if.end", mCurFunc);

  irb.CreateCondBr(emitCondition(obj->cond), thenBb, obj->else_ ? elseBb : endBb);

  mCurIrb->SetInsertPoint(thenBb);
  self(obj->then);
  if (!currentBlockTerminated())
    irb.CreateBr(endBb);

  if (obj->else_) {
    mCurIrb->SetInsertPoint(elseBb);
    self(obj->else_);
    if (!currentBlockTerminated())
      irb.CreateBr(endBb);
  }

  mCurIrb->SetInsertPoint(endBb);
}

void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;
  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto endBb = llvm::BasicBlock::Create(mCtx, "while.end", mCurFunc);

  irb.CreateBr(condBb);
  mCurIrb->SetInsertPoint(condBb);
  irb.CreateCondBr(emitCondition(obj->cond), bodyBb, endBb);

  mBreakTargets.push_back(endBb);
  mContinueTargets.push_back(condBb);
  mCurIrb->SetInsertPoint(bodyBb);
  self(obj->body);
  if (!currentBlockTerminated())
    irb.CreateBr(condBb);
  mContinueTargets.pop_back();
  mBreakTargets.pop_back();

  mCurIrb->SetInsertPoint(endBb);
}

void
EmitIR::operator()(BreakStmt* obj)
{
  ASSERT(!mBreakTargets.empty());
  mCurIrb->CreateBr(mBreakTargets.back());
}

void
EmitIR::operator()(ContinueStmt* obj)
{
  ASSERT(!mContinueTargets.empty());
  mCurIrb->CreateBr(mContinueTargets.back());
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;
  if (!obj->expr) {
    irb.CreateRetVoid();
  } else {
    auto retVal = self(obj->expr);
    retVal = castTo(retVal, mCurFunc->getReturnType());
    irb.CreateRet(retVal);
  }
}

//==============================================================================
// 声明
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);
  if (auto p = obj->dcst<VarDecl>())
    return self(p);
  ABORT();
}

llvm::AllocaInst*
EmitIR::createEntryAlloca(llvm::Type* type, llvm::StringRef name)
{
  llvm::IRBuilder<> tmp(&mCurFunc->getEntryBlock(), mCurFunc->getEntryBlock().begin());
  return tmp.CreateAlloca(type, nullptr, name);
}

void
EmitIR::declareGlobal(VarDecl* obj)
{
  if (obj->any)
    return;
  auto ty = self(obj->type);
  auto init = constInit(obj->type, obj->init);
  auto gv = new llvm::GlobalVariable(
    mMod,
    ty,
    obj->type->qual.const_,
    llvm::GlobalValue::ExternalLinkage,
    init,
    obj->name);
  obj->any = gv;
}

void
EmitIR::declareFunction(FunctionDecl* obj)
{
  if (obj->any)
    return;
  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
  ASSERT(fty);
  auto func = llvm::Function::Create(
    fty, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);
  obj->any = func;
}

void
EmitIR::operator()(FunctionDecl* obj)
{
  declareFunction(obj);
}

void
EmitIR::emitFunctionBody(FunctionDecl* obj)
{
  if (obj->body == nullptr)
    return;

  auto func = static_cast<llvm::Function*>(obj->any);
  if (!func->empty())
    return;

  mCurFunc = func;
  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);

  auto argIt = func->arg_begin();
  for (std::size_t i = 0; i < obj->params.size(); ++i, ++argIt) {
    auto param = obj->params[i];
    auto alloca = createEntryAlloca(argIt->getType(), param->name);
    mCurIrb->CreateStore(&*argIt, alloca);
    param->any = alloca;
  }

  self(obj->body);

  if (!currentBlockTerminated()) {
    if (func->getReturnType()->isVoidTy())
      mCurIrb->CreateRetVoid();
    else
      mCurIrb->CreateRet(llvm::Constant::getNullValue(func->getReturnType()));
  }

  mCurFunc = nullptr;
}

void
EmitIR::operator()(VarDecl* obj)
{
  if (!mCurFunc) {
    declareGlobal(obj);
    return;
  }

  auto ty = self(obj->type);
  auto addr = createEntryAlloca(ty, obj->name);
  obj->any = addr;
  emitLocalInit(addr, obj->type, obj->init);
}

void
EmitIR::emitLocalInit(llvm::Value* addr, const Type* type, Expr* init)
{
  auto& irb = *mCurIrb;
  if (!init) {
    irb.CreateStore(zeroOf(type), addr);
    return;
  }

  if (auto arrTy = type->texp ? type->texp->dcst<ArrayType>() : nullptr) {
    Type elemTy;
    elemTy.spec = type->spec;
    elemTy.qual = type->qual;
    elemTy.texp = arrTy->sub;
    auto zero = llvm::ConstantInt::get(mIntTy, 0);
    auto list = init->dcst<InitListExpr>();
    for (std::uint32_t i = 0; i < arrTy->len; ++i) {
      auto idx = llvm::ConstantInt::get(mIntTy, i);
      auto elemAddr = irb.CreateInBoundsGEP(self(type), addr, { zero, idx });
      Expr* elemInit = (list && i < list->list.size()) ? list->list[i] : nullptr;
      emitLocalInit(elemAddr, &elemTy, elemInit);
    }
    return;
  }

  if (auto list = init->dcst<InitListExpr>()) {
    if (list->list.empty())
      irb.CreateStore(zeroOf(type), addr);
    else
      emitLocalInit(addr, type, list->list.front());
    return;
  }

  if (auto impl = init->dcst<ImplicitInitExpr>()) {
    irb.CreateStore(zeroOf(type), addr);
    return;
  }

  auto val = self(init);
  val = castTo(val, self(type));
  irb.CreateStore(val, addr);
}
