#include "SimpleOpt.hpp"

#include <llvm/ADT/SmallPtrSet.h>
#include <llvm/IR/Constants.h>
#include <llvm/IR/Function.h>
#include <llvm/IR/GlobalVariable.h>
#include <llvm/IR/IRBuilder.h>
#include <llvm/IR/InstrTypes.h>
#include <llvm/IR/Instructions.h>
#include <llvm/IR/Module.h>
#include <llvm/IR/Operator.h>
#include <llvm/Support/MathExtras.h>
#include <queue>

using namespace llvm;

namespace {

ConstantInt* cint(Value* v)
{
  return dyn_cast<ConstantInt>(v);
}

bool isZero(Value* v)
{
  auto c = cint(v);
  return c && c->isZero();
}

bool isOne(Value* v)
{
  auto c = cint(v);
  return c && c->isOne();
}

ConstantInt* intConst(Type* ty, int64_t v)
{
  return ConstantInt::get(ty, v, true);
}

bool sameConst(ConstantInt* a, ConstantInt* b)
{
  return a && b && a->getBitWidth() == b->getBitWidth() &&
         a->getValue() == b->getValue();
}

bool hasOnlyDirectCalls(Function& f)
{
  for (User* u : f.users()) {
    auto cb = dyn_cast<CallBase>(u);
    if (!cb || cb->getCalledFunction() != &f)
      return false;
  }
  return true;
}

bool propagateConstantArgs(Module& mod)
{
  bool changed = false;
  for (Function& f : mod) {
    if (f.isDeclaration() || f.getName() == "main" || !hasOnlyDirectCalls(f))
      continue;
    if (f.user_empty())
      continue;

    std::vector<ConstantInt*> common(f.arg_size(), nullptr);
    std::vector<bool> known(f.arg_size(), true);
    bool firstCall = true;
    for (User* u : f.users()) {
      auto cb = cast<CallBase>(u);
      for (unsigned i = 0; i < f.arg_size(); ++i) {
        auto c = dyn_cast<ConstantInt>(cb->getArgOperand(i));
        if (firstCall)
          common[i] = c;
        else if (!sameConst(common[i], c))
          known[i] = false;
        if (!c)
          known[i] = false;
      }
      firstCall = false;
    }

    unsigned i = 0;
    for (Argument& arg : f.args()) {
      if (known[i] && common[i] && !arg.use_empty()) {
        arg.replaceAllUsesWith(common[i]);
        changed = true;
      }
      ++i;
    }
  }
  return changed;
}

bool globalNeverStored(GlobalVariable* gv)
{
  for (User* u : gv->users()) {
    if (auto li = dyn_cast<LoadInst>(u))
      continue;
    if (auto ce = dyn_cast<ConstantExpr>(u)) {
      for (User* uu : ce->users()) {
        if (!isa<LoadInst>(uu))
          return false;
      }
      continue;
    }
    return false;
  }
  return true;
}

bool propagateGlobalConstants(Module& mod)
{
  bool changed = false;
  for (GlobalVariable& gv : mod.globals()) {
    if (!gv.hasInitializer())
      continue;
    auto init = dyn_cast<ConstantInt>(gv.getInitializer());
    if (!init || !globalNeverStored(&gv))
      continue;

    std::vector<Instruction*> erase;
    for (User* u : make_early_inc_range(gv.users())) {
      if (auto li = dyn_cast<LoadInst>(u)) {
        li->replaceAllUsesWith(init);
        erase.push_back(li);
        changed = true;
      }
    }
    for (auto i : erase)
      i->eraseFromParent();
  }
  return changed;
}

struct AddDecomp
{
  Value* base;
  APInt c;
};

AddDecomp decomposeAdd(Value* v, unsigned depth = 0)
{
  if (auto c = cint(v))
    return { ConstantInt::get(v->getType(), 0), c->getValue() };
  if (depth > 64)
    return { v, APInt(v->getType()->getIntegerBitWidth(), 0) };

  auto bo = dyn_cast<BinaryOperator>(v);
  if (!bo || !bo->hasOneUse() || !v->getType()->isIntegerTy())
    return { v, APInt(v->getType()->getIntegerBitWidth(), 0) };

  if (bo->getOpcode() == Instruction::Add) {
    if (auto c = cint(bo->getOperand(1))) {
      auto d = decomposeAdd(bo->getOperand(0), depth + 1);
      d.c += c->getValue();
      return d;
    }
    if (auto c = cint(bo->getOperand(0))) {
      auto d = decomposeAdd(bo->getOperand(1), depth + 1);
      d.c += c->getValue();
      return d;
    }
  }
  if (bo->getOpcode() == Instruction::Sub) {
    if (auto c = cint(bo->getOperand(1))) {
      auto d = decomposeAdd(bo->getOperand(0), depth + 1);
      d.c -= c->getValue();
      return d;
    }
  }
  return { v, APInt(v->getType()->getIntegerBitWidth(), 0) };
}

Value* makeAdd(IRBuilder<>& b, Instruction* old, Value* base, APInt c)
{
  if (c.isZero())
    return base;
  auto cc = ConstantInt::get(old->getType(), c);
  if (isa<ConstantInt>(base))
    return ConstantInt::get(old->getType(), c);
  auto ni = b.CreateAdd(base, cc);
  if (auto ob = dyn_cast<BinaryOperator>(old)) {
    if (ob->hasNoSignedWrap())
      cast<BinaryOperator>(ni)->setHasNoSignedWrap();
    if (ob->hasNoUnsignedWrap())
      cast<BinaryOperator>(ni)->setHasNoUnsignedWrap();
  }
  return ni;
}

Constant* foldBinaryConst(BinaryOperator* bo, ConstantInt* l, ConstantInt* r)
{
  auto ty = bo->getType();
  auto a = l->getValue();
  auto b = r->getValue();
  switch (bo->getOpcode()) {
    case Instruction::Add: return ConstantInt::get(ty, a + b);
    case Instruction::Sub: return ConstantInt::get(ty, a - b);
    case Instruction::Mul: return ConstantInt::get(ty, a * b);
    case Instruction::SDiv:
      if (b.isZero()) return nullptr;
      return ConstantInt::get(ty, a.sdiv(b));
    case Instruction::SRem:
      if (b.isZero()) return nullptr;
      return ConstantInt::get(ty, a.srem(b));
    case Instruction::UDiv:
      if (b.isZero()) return nullptr;
      return ConstantInt::get(ty, a.udiv(b));
    case Instruction::URem:
      if (b.isZero()) return nullptr;
      return ConstantInt::get(ty, a.urem(b));
    case Instruction::Shl: return ConstantInt::get(ty, a.shl(b));
    case Instruction::AShr: return ConstantInt::get(ty, a.ashr(b));
    case Instruction::LShr: return ConstantInt::get(ty, a.lshr(b));
    case Instruction::And: return ConstantInt::get(ty, a & b);
    case Instruction::Or: return ConstantInt::get(ty, a | b);
    case Instruction::Xor: return ConstantInt::get(ty, a ^ b);
    default: return nullptr;
  }
}

Value* simplifyBinary(BinaryOperator* bo)
{
  auto lhs = bo->getOperand(0);
  auto rhs = bo->getOperand(1);
  auto lc = cint(lhs);
  auto rc = cint(rhs);
  if (lc && rc)
    if (auto c = foldBinaryConst(bo, lc, rc))
      return c;

  IRBuilder<> b(bo);
  switch (bo->getOpcode()) {
    case Instruction::Add: {
      if (isZero(rhs)) return lhs;
      if (isZero(lhs)) return rhs;
      if (rc || lc) {
        auto var = rc ? lhs : rhs;
        auto c = rc ? rc : lc;
        auto d = decomposeAdd(var);
        d.c += c->getValue();
        if (d.base != var || d.c != c->getValue())
          return makeAdd(b, bo, d.base, d.c);
      }
      break;
    }
    case Instruction::Sub: {
      if (isZero(rhs)) return lhs;
      if (lhs == rhs) return ConstantInt::get(bo->getType(), 0);
      if (rc) {
        auto d = decomposeAdd(lhs);
        d.c -= rc->getValue();
        if (d.base != lhs || !d.c.isZero())
          return makeAdd(b, bo, d.base, d.c);
      }
      break;
    }
    case Instruction::Mul: {
      if (isZero(lhs) || isZero(rhs)) return ConstantInt::get(bo->getType(), 0);
      if (isOne(lhs)) return rhs;
      if (isOne(rhs)) return lhs;
      break;
    }
    case Instruction::SDiv:
    case Instruction::UDiv: {
      if (isZero(lhs)) return ConstantInt::get(bo->getType(), 0);
      if (isOne(rhs)) return lhs;
      if (auto rcst = cint(rhs)) {
        if (auto mul = dyn_cast<BinaryOperator>(lhs)) {
          if (mul->getOpcode() == Instruction::Mul && mul->hasNoSignedWrap()) {
            if (sameConst(dyn_cast<ConstantInt>(mul->getOperand(1)), rcst))
              return mul->getOperand(0);
            if (sameConst(dyn_cast<ConstantInt>(mul->getOperand(0)), rcst))
              return mul->getOperand(1);
          }
        }
      }
      break;
    }
    case Instruction::SRem:
    case Instruction::URem: {
      if (isZero(lhs) || isOne(rhs)) return ConstantInt::get(bo->getType(), 0);
      if (auto rcst = cint(rhs)) {
        if (auto mul = dyn_cast<BinaryOperator>(lhs)) {
          if (mul->getOpcode() == Instruction::Mul && mul->hasNoSignedWrap() &&
              (sameConst(dyn_cast<ConstantInt>(mul->getOperand(0)), rcst) ||
               sameConst(dyn_cast<ConstantInt>(mul->getOperand(1)), rcst)))
            return ConstantInt::get(bo->getType(), 0);
        }
      }
      break;
    }
    case Instruction::And: {
      if (isZero(lhs) || isZero(rhs)) return ConstantInt::get(bo->getType(), 0);
      if (lhs == rhs) return lhs;
      break;
    }
    case Instruction::Or: {
      if (isZero(lhs)) return rhs;
      if (isZero(rhs)) return lhs;
      if (lhs == rhs) return lhs;
      break;
    }
    case Instruction::Xor: {
      if (isZero(lhs)) return rhs;
      if (isZero(rhs)) return lhs;
      if (lhs == rhs) return ConstantInt::get(bo->getType(), 0);
      break;
    }
    default:
      break;
  }
  return nullptr;
}

Value* simplifyInstructionLocal(Instruction* inst)
{
  if (auto bo = dyn_cast<BinaryOperator>(inst))
    return simplifyBinary(bo);

  if (auto icmp = dyn_cast<ICmpInst>(inst)) {
    auto lhs = icmp->getOperand(0);
    auto rhs = icmp->getOperand(1);
    if (lhs == rhs) {
      bool v = false;
      switch (icmp->getPredicate()) {
        case CmpInst::ICMP_EQ:
        case CmpInst::ICMP_SGE:
        case CmpInst::ICMP_SLE:
        case CmpInst::ICMP_UGE:
        case CmpInst::ICMP_ULE: v = true; break;
        default: v = false; break;
      }
      return ConstantInt::get(inst->getType(), v);
    }
    if (auto l = cint(lhs)) {
      if (auto r = cint(rhs)) {
        return ConstantInt::get(inst->getType(), ICmpInst::compare(l->getValue(), r->getValue(), icmp->getPredicate()));
      }
    }
  }

  if (auto ci = dyn_cast<CastInst>(inst)) {
    auto op = ci->getOperand(0);
    if (op->getType() == ci->getType())
      return op;
    if (auto c = cint(op)) {
      switch (ci->getOpcode()) {
        case Instruction::SExt: return ConstantInt::get(ci->getType(), c->getSExtValue(), true);
        case Instruction::ZExt: return ConstantInt::get(ci->getType(), c->getZExtValue(), false);
        case Instruction::Trunc: return ConstantInt::get(ci->getType(), c->getValue().trunc(ci->getType()->getIntegerBitWidth()));
        default: break;
      }
    }
  }

  if (auto phi = dyn_cast<PHINode>(inst)) {
    Value* common = nullptr;
    for (Value* v : phi->incoming_values()) {
      if (isa<UndefValue>(v))
        continue;
      if (!common)
        common = v;
      else if (common != v)
        return nullptr;
    }
    if (common)
      return common;
  }

  return nullptr;
}

bool simplifyInstructions(Module& mod)
{
  bool changed = false;
  for (Function& f : mod) {
    if (f.isDeclaration()) continue;
    for (BasicBlock& bb : f) {
      for (Instruction& inst : make_early_inc_range(bb)) {
        if (auto repl = simplifyInstructionLocal(&inst)) {
          if (repl != &inst) {
            inst.replaceAllUsesWith(repl);
            if (inst.use_empty() && !inst.isTerminator())
              inst.eraseFromParent();
            changed = true;
          }
        }
      }
    }
  }
  return changed;
}

bool simplifyBranches(Module& mod)
{
  bool changed = false;
  for (Function& f : mod) {
    if (f.isDeclaration()) continue;
    for (BasicBlock& bb : f) {
      auto br = dyn_cast<BranchInst>(bb.getTerminator());
      if (!br || !br->isConditional()) continue;
      auto c = dyn_cast<ConstantInt>(br->getCondition());
      if (!c) continue;
      auto target = br->getSuccessor(c->isZero() ? 1 : 0);
      BranchInst::Create(target, br);
      br->eraseFromParent();
      changed = true;
    }
  }
  return changed;
}

bool removeDeadInsts(Module& mod)
{
  bool changed = false;
  bool local = true;
  while (local) {
    local = false;
    for (Function& f : mod) {
      if (f.isDeclaration()) continue;
      for (BasicBlock& bb : f) {
        for (Instruction& inst : make_early_inc_range(bb)) {
          if (inst.isTerminator()) continue;
          if (inst.use_empty() && !inst.mayHaveSideEffects() && !isa<AllocaInst>(&inst)) {
            inst.eraseFromParent();
            local = changed = true;
          }
        }
      }
    }
  }
  return changed;
}

bool removeUnreachableBlocks(Module& mod)
{
  bool changed = false;
